    39→/* ---------------------------------------------------------------------------
    40→ * Logger shim
    41→ * -------------------------------------------------------------------------*/
    42→#ifndef MM_LOGGER_H
    43→/*  In production builds <mm_logger.h> is available globally.                 */
    44→/*  We provide a fallback to keep this unit self-contained for unit tests.    */
    45→typedef enum { LOG_DEBUG, LOG_INFO, LOG_WARN, LOG_ERROR } mm_log_level_t;
    46→
    47→static inline void mm_log(mm_log_level_t lvl, const char *fmt, ...)
    48→{
    49→    const char *lvl_str = (lvl == LOG_DEBUG) ? "DEBUG" :
    50→                          (lvl == LOG_INFO)  ? "INFO"  :
    51→                          (lvl == LOG_WARN)  ? "WARN"  : "ERROR";
    52→
    53→    va_list ap;
    54→    va_start(ap, fmt);
    55→    fprintf(stderr, "[%s] ", lvl_str);
    56→    vfprintf(stderr, fmt, ap);
    57→    fprintf(stderr, "\n");
    58→    va_end(ap);
    59→}
    60→#endif /* MM_LOGGER_H */
