    63→/* ---------------------------------------------------------------------------
    64→ * Constants & Macros
    65→ * -------------------------------------------------------------------------*/
    66→#define MM_CACHE_MODULE_VERSION  "31.3.0"   /* Semantic versioning       */
    67→
    68→#define MM_CACHE_DEFAULT_TBL_SIZE  2048u    /* Must be power-of-two      */
    69→#define MM_CACHE_MIN_TTL           1u       /* Seconds                   */
    70→#define MM_CACHE_MAX_KEYLEN        1024u
    71→#define MM_CACHE_MAX_CONTENTTYPE   128u
    72→#define MM_CACHE_MAX_ETAG          128u
    73→
    74→#define unlikely(x) __builtin_expect(!!(x), 0)
    75→
    76→/* ---------------------------------------------------------------------------
    77→ * Data Types
    78→ * -------------------------------------------------------------------------*/
    79→typedef struct mm_cache_entry {
    80→    char              *key;
    81→    unsigned char     *payload;
    82→    size_t             payload_len;
    83→
    84→    char              *content_type;        /* MIME type (optional)  */
    85→    char              *etag;                /* Strong/Weak ETag      */
    86→
    87→    time_t             expiry_ts;           /* Epoch time            */
    88→    uint64_t           last_access;         /* Monotonic counter     */
    89→
    90→    struct mm_cache_entry *prev, *next;     /* LRU list              */
    91→} mm_cache_entry_t;
    92→
    93→typedef struct {
    94→    /* Configuration */
    95→    size_t   capacity_bytes;   /* Max RAM in bytes                    */
    96→    size_t   max_entries;      /* Cap on element count                */
    97→
    98→    /* Internal state */
    99→    size_t   current_bytes;
   100→    size_t   entry_count;
   101→    size_t   tbl_size;         /* Hash table size (power of two)      */
   102→    mm_cache_entry_t **table;
   103→
   104→    mm_cache_entry_t *lru_head;/* MRU                                 */
   105→    mm_cache_entry_t *lru_tail;/* LRU                                 */
   106→
   107→    /* Concurrency control */
   108→    pthread_rwlock_t rwlock;
   109→
   110→    /* Metrics */
   111→    uint64_t hits;
   112→    uint64_t misses;
   113→    uint64_t evictions;
   114→} mm_cache_t;
