   140→/*
   141→ * mm_cache_init
   142→ * ----------------------------------------------------------------------------
   143→ * Initializes a response cache instance.
   144→ *
   145→ * Arguments:
   146→ *   c               – pointer to an allocated mm_cache_t
   147→ *   max_entries     – upper bound on number of cache records
   148→ *   capacity_bytes  – max memory usage for payloads + metadata
   149→ *
   150→ * Return:
   151→ *   0 on success, errno-compatible error code otherwise.
   152→ */
   153→int mm_cache_init(mm_cache_t *c,
   154→                  size_t max_entries,
   155→                  size_t capacity_bytes)
   156→{
   157→    if (!c || max_entries == 0 || capacity_bytes == 0)
   158→        return EINVAL;
   159→
   160→    memset(c, 0, sizeof(*c));
   161→
   162→    c->max_entries    = max_entries;
   163→    c->capacity_bytes = capacity_bytes;
   164→
   165→    /* Initial hash table size: next power-of-two >= max_entries * 2          */
   166→    size_t tbl_size = MM_CACHE_DEFAULT_TBL_SIZE;
   167→    while (tbl_size < (max_entries << 1)) tbl_size <<= 1;
   168→
   169→    if (mm_cache_grow_table(c, tbl_size) != 0)
   170→        return ENOMEM;
   171→
   172→    if (pthread_rwlock_init(&c->rwlock, NULL) != 0)
   173→        return errno;
   174→
   175→    mm_log(LOG_INFO, "Response cache initialized (ver=%s, max_entries=%zu, "
   176→                     "capacity=%zu KiB)",
   177→                     MM_CACHE_MODULE_VERSION,
   178→                     max_entries,
   179→                     capacity_bytes >> 10);
   180→    return 0;
   181→}
   182→
   183→/*
   184→ * mm_cache_destroy
   185→ * ----------------------------------------------------------------------------
   186→ * Frees all memory associated with the cache.
   187→ */
   188→void mm_cache_destroy(mm_cache_t *c)
   189→{
   190→    if (!c) return;
   191→
   192→    pthread_rwlock_wrlock(&c->rwlock);
   193→
   194→    for (size_t i = 0; i < c->tbl_size; ++i) {
   195→        mm_cache_entry_t *e = c->table[i];
   196→        if (e) {
   197→            free(e->key);
   198→            free(e->payload);
   199→            free(e->content_type);
   200→            free(e->etag);
   201→            free(e);
   202→        }
   203→    }
   204→    free(c->table);
   205→
   206→    pthread_rwlock_unlock(&c->rwlock);
   207→    pthread_rwlock_destroy(&c->rwlock);
   208→    memset(c, 0, sizeof(*c));
   209→}
   210→
   211→/*
   212→ * mm_cache_put
   213→ * ----------------------------------------------------------------------------
   214→ * Stores a response in the cache.
   215→ *
   216→ * The cache takes ownership of the payload data (it copies it internally).
   217→ *
   218→ * Arguments:
   219→ *   key             – request hash key  (string)
   220→ *   payload         – response body
   221→ *   payload_len     – size of response body
   222→ *   content_type    – MIME type (may be NULL)
   223→ *   etag            – optional ETag header
   224→ *   ttl_seconds     – time-to-live for this cache record
   225→ *
   226→ * Return:
   227→ *   0 on success, errno code on failure
   228→ */
   229→int mm_cache_put(mm_cache_t *c,
   230→                 const char *key,
   231→                 const unsigned char *payload,
   232→                 size_t payload_len,
   233→                 const char *content_type,
   234→                 const char *etag,
   235→                 uint32_t ttl_seconds)
   236→{
   237→    if (!c || !key || !payload || payload_len == 0)
   238→        return EINVAL;
   239→
   240→    if (strlen(key) > MM_CACHE_MAX_KEYLEN)
   241→        return ENAMETOOLONG;
   242→
   243→    if (ttl_seconds < MM_CACHE_MIN_TTL)
   244→        ttl_seconds = MM_CACHE_MIN_TTL;
   245→
   246→    /* Pre-allocate memory before acquiring write lock to minimize lock time */
   247→    mm_cache_entry_t *new_entry = calloc(1, sizeof(*new_entry));
   248→    if (!new_entry)
   249→        return ENOMEM;
   250→
   251→    new_entry->key = strdup(key);
   252→    if (!new_entry->key) { free(new_entry); return ENOMEM; }
   253→
   254→    new_entry->payload = malloc(payload_len);
   255→    if (!new_entry->payload) { free(new_entry->key); free(new_entry); return ENOMEM; }
   256→    memcpy(new_entry->payload, payload, payload_len);
   257→    new_entry->payload_len = payload_len;
   258→
   259→    if (content_type) {
   260→        if (strlen(content_type) > MM_CACHE_MAX_CONTENTTYPE) {
   261→            free(new_entry->payload); free(new_entry->key); free(new_entry);
   262→            return ENAMETOOLONG;
   263→        }
   264→        new_entry->content_type = strdup(content_type);
   265→        if (!new_entry->content_type) goto oom;
   266→    }
   267→
   268→    if (etag) {
   269→        if (strlen(etag) > MM_CACHE_MAX_ETAG) {
   270→            free(new_entry->content_type); free(new_entry->payload);
   271→            free(new_entry->key); free(new_entry); return ENAMETOOLONG;
   272→        }
   273→        new_entry->etag = strdup(etag);
   274→        if (!new_entry->etag) goto oom;
   275→    }
   276→
   277→    new_entry->expiry_ts   = time(NULL) + ttl_seconds;
   278→    new_entry->last_access = (uint64_t)clock();
   279→
   280→    /* Lock and insert */
   281→    pthread_rwlock_wrlock(&c->rwlock);
   282→
   283→    /* Evict expired + ensure capacity before insertion */
   284→    mm_cache_evict_if_needed(c, payload_len);
   285→
   286→    uint64_t hash = mm_fnv1a_hash(key, strlen(key));
   287→    size_t idx = hash & (c->tbl_size - 1);
   288→
   289→    while (c->table[idx] && strcmp(c->table[idx]->key, key) != 0)
   290→        idx = (idx + 1) & (c->tbl_size - 1);
   291→
   292→    mm_cache_entry_t *existing = c->table[idx];
   293→    if (existing) {
   294→        /* Replace existing entry */
   295→        c->current_bytes -= existing->payload_len;
   296→        free(existing->payload);
   297→        existing->payload       = new_entry->payload;
   298→        existing->payload_len   = new_entry->payload_len;
   299→        existing->expiry_ts     = new_entry->expiry_ts;
   300→        existing->last_access   = new_entry->last_access;
   301→
   302→        free(existing->content_type);
   303→        existing->content_type  = new_entry->content_type;
   304→
   305→        free(existing->etag);
   306→        existing->etag          = new_entry->etag;
   307→
   308→        /* Touch */
   309→        mm_cache_lru_touch(c, existing);
   310→
   311→        free(new_entry->key); /* key identical */
   312→        free(new_entry);      /* container freed */
   313→    } else {
   314→        /* Insert brand new entry */
   315→        c->table[idx] = new_entry;
   316→        c->entry_count++;
   317→        c->current_bytes += payload_len;
   318→
   319→        /* Add to LRU head */
   320→        new_entry->next = c->lru_head;
   321→        if (c->lru_head)
   322→            c->lru_head->prev = new_entry;
   323→        c->lru_head = new_entry;
   324→        if (!c->lru_tail)
   325→            c->lru_tail = new_entry;
   326→    }
   327→
   328→    pthread_rwlock_unlock(&c->rwlock);
   329→    return 0;
   330→
   331→oom:
   332→    free(new_entry->etag);
   333→    free(new_entry->content_type);
   334→    free(new_entry->payload);
   335→    free(new_entry->key);
   336→    free(new_entry);
   337→    return ENOMEM;
   338→}
   339→
   340→/*
   341→ * mm_cache_get
   342→ * ----------------------------------------------------------------------------
   343→ * Retrieves a cached response. Ownership of *payload_out is transferred to
   344→ * the caller (caller must free). content_type_out & etag_out point to
   345→ * internal strings – do not free, DO copy if retained beyond processing.
   346→ *
   347→ * Return:
   348→ *   1  – cache HIT  (payload populated)
   349→ *   0  – cache MISS
   350→ *  <0  – negative errno on internal failure
   351→ */
   352→int mm_cache_get(mm_cache_t *c,
   353→                 const char *key,
   354→                 unsigned char **payload_out,
   355→                 size_t *payload_len_out,
   356→                 const char **content_type_out,
   357→                 const char **etag_out,
   358→                 uint32_t *age_out)
   359→{
   360→    if (!c || !key || !payload_out || !payload_len_out)
   361→        return -EINVAL;
   362→
   363→    pthread_rwlock_rdlock(&c->rwlock);
   364→
   365→    uint64_t hash = mm_fnv1a_hash(key, strlen(key));
   366→    size_t idx = hash & (c->tbl_size - 1);
   367→
   368→    while (c->table[idx] && strcmp(c->table[idx]->key, key) != 0)
   369→        idx = (idx + 1) & (c->tbl_size - 1);
   370→
   371→    mm_cache_entry_t *e = c->table[idx];
   372→
   373→    /* Fast path: MISS */
   374→    if (!e) {
   375→        c->misses++;
   376→        pthread_rwlock_unlock(&c->rwlock);
   377→        return 0;
   378→    }
   379→
   380→    /* Check expiration */
   381→    time_t now = time(NULL);
   382→    if (e->expiry_ts < now) {
   383→        /* Upgrade to write lock to remove expired entry */
   384→        pthread_rwlock_unlock(&c->rwlock);
   385→        pthread_rwlock_wrlock(&c->rwlock);
   386→
   387→        /* ensure another thread hasn't removed it */
   388→        if (c->table[idx] == e) {
   389→            /* Detach from LRU */
   390→            if (e->prev) e->prev->next = e->next;
   391→            if (e->next) e->next->prev = e->prev;
   392→            if (e == c->lru_head) c->lru_head = e->next;
   393→            if (e == c->lru_tail) c->lru_tail = e->prev;
   394→
   395→            /* Hash slot removal */
   396→            c->table[idx] = NULL;
   397→            c->entry_count--;
   398→            c->current_bytes -= e->payload_len;
   399→
   400→            /* Rehash cluster (Robin Hood deletion not necessary for small table) */
   401→            size_t j = (idx + 1) & (c->tbl_size - 1);
   402→            while (c->table[j]) {
   403→                mm_cache_entry_t *move = c->table[j];
   404→                c->table[j] = NULL;
   405→
   406→                size_t new_idx = mm_fnv1a_hash(move->key, strlen(move->key)) & (c->tbl_size - 1);
   407→                while (c->table[new_idx])
   408→                    new_idx = (new_idx + 1) & (c->tbl_size - 1);
   409→                c->table[new_idx] = move;
   410→                j = (j + 1) & (c->tbl_size - 1);
   411→            }
   412→
   413→            free(e->key);
   414→            free(e->payload);
   415→            free(e->content_type);
   416→            free(e->etag);
   417→            free(e);
   418→        }
   419→
   420→        c->misses++;
   421→        pthread_rwlock_unlock(&c->rwlock);
   422→        return 0;
   423→    }
   424→
   425→    /* HIT */
   426→    e->last_access = (uint64_t)clock();
   427→    c->hits++;
   428→
   429→    /* Copy payload for caller */
   430→    unsigned char *payload_dup = malloc(e->payload_len);
   431→    if (!payload_dup) {
   432→        pthread_rwlock_unlock(&c->rwlock);
   433→        return -ENOMEM;
   434→    }
   435→    memcpy(payload_dup, e->payload, e->payload_len);
   436→
   437→    *payload_out      = payload_dup;
   438→    *payload_len_out  = e->payload_len;
   439→    if (content_type_out) *content_type_out = e->content_type;
   440→    if (etag_out)        *etag_out          = e->etag;
   441→    if (age_out)         *age_out           = (uint32_t)(now - (e->expiry_ts - now));
   442→
   443→    /* Defer LRU touch after releasing read lock to cut contention.          */
   444→    pthread_rwlock_unlock(&c->rwlock);
   445→
   446→    pthread_rwlock_wrlock(&c->rwlock);
   447→    mm_cache_lru_touch(c, e);
   448→    pthread_rwlock_unlock(&c->rwlock);
   449→
   450→    return 1;
   451→}
