   453→/*
   454→ * mm_cache_invalidate
   455→ * ----------------------------------------------------------------------------
   456→ * Removes a single entry from the cache (e.g. after POST/PUT/DELETE).
   457→ */
   458→void mm_cache_invalidate(mm_cache_t *c, const char *key)
   459→{
   460→    if (!c || !key) return;
   461→    pthread_rwlock_wrlock(&c->rwlock);
   462→
   463→    uint64_t hash = mm_fnv1a_hash(key, strlen(key));
   464→    size_t idx = hash & (c->tbl_size - 1);
   465→
   466→    while (c->table[idx] && strcmp(c->table[idx]->key, key) != 0)
   467→        idx = (idx + 1) & (c->tbl_size - 1);
   468→
   469→    mm_cache_entry_t *e = c->table[idx];
   470→    if (!e) {
   471→        pthread_rwlock_unlock(&c->rwlock);
   472→        return;
   473→    }
   474→
   475→    /* Detach */
   476→    if (e->prev) e->prev->next = e->next;
   477→    if (e->next) e->next->prev = e->prev;
   478→    if (e == c->lru_head) c->lru_head = e->next;
   479→    if (e == c->lru_tail) c->lru_tail = e->prev;
   480→
   481→    c->table[idx] = NULL;
   482→    c->entry_count--;
   483→    c->current_bytes -= e->payload_len;
   484→
   485→    /* Rehash cluster */
   486→    size_t j = (idx + 1) & (c->tbl_size - 1);
   487→    while (c->table[j]) {
   488→        mm_cache_entry_t *move = c->table[j];
   489→        c->table[j] = NULL;
   490→
   491→        size_t new_idx = mm_fnv1a_hash(move->key, strlen(move->key)) & (c->tbl_size - 1);
   492→        while (c->table[new_idx])
   493→            new_idx = (new_idx + 1) & (c->tbl_size - 1);
   494→        c->table[new_idx] = move;
   495→
   496→        j = (j + 1) & (c->tbl_size - 1);
   497→    }
   498→
   499→    free(e->key);
   500→    free(e->payload);
   501→    free(e->content_type);
   502→    free(e->etag);
   503→    free(e);
   504→
   505→    pthread_rwlock_unlock(&c->rwlock);
   506→    mm_log(LOG_DEBUG, "Cache invalidated: %s", key);
   507→}
