   509→/*
   510→ * mm_cache_purge
   511→ * ----------------------------------------------------------------------------
   512→ * Removes every entry from the cache.
   513→ */
   514→void mm_cache_purge(mm_cache_t *c)
   515→{
   516→    if (!c) return;
   517→    pthread_rwlock_wrlock(&c->rwlock);
   518→
   519→    for (size_t i = 0; i < c->tbl_size; ++i) {
   520→        mm_cache_entry_t *e = c->table[i];
   521→        if (e) {
   522→            free(e->key);
   523→            free(e->payload);
   524→            free(e->content_type);
   525→            free(e->etag);
   526→            free(e);
   527→        }
   528→        c->table[i] = NULL;
   529→    }
   530→
   531→    c->entry_count   = 0;
   532→    c->current_bytes = 0;
   533→    c->lru_head = c->lru_tail = NULL;
   534→
   535→    pthread_rwlock_unlock(&c->rwlock);
   536→    mm_log(LOG_INFO, "Cache fully purged");
   537→}
