   539→/*
   540→ * mm_cache_metrics_snapshot
   541→ * ----------------------------------------------------------------------------
   542→ * Captures a read-only snapshot of metrics for Prometheus scrape thread.
   543→ */
   544→void mm_cache_metrics_snapshot(const mm_cache_t *c,
   545→                               mm_cache_metrics_t *out)
   546→{
   547→    if (!c || !out) return;
   548→    pthread_rwlock_rdlock((pthread_rwlock_t *)&c->rwlock);
   549→
   550→    out->hits          = c->hits;
   551→    out->misses        = c->misses;
   552→    out->evictions     = c->evictions;
   553→    out->entry_count   = c->entry_count;
   554→    out->current_bytes = c->current_bytes;
   555→
   556→    pthread_rwlock_unlock((pthread_rwlock_t *)&c->rwlock);
   557→}
