   559→/* ---------------------------------------------------------------------------
   560→ * INTERNAL HELPERS
   561→ * -------------------------------------------------------------------------*/
   562→
   563→/* Fowler-Noll-Vo hash */
   564→static uint64_t mm_fnv1a_hash(const void *data, size_t len)
   565→{
   566→    const uint8_t *p = (const uint8_t *)data;
   567→    uint64_t h = 14695981039346656037ULL; /* offset basis */
   568→    for (size_t i = 0; i < len; ++i) {
   569→        h ^= (uint64_t)p[i];
   570→        h *= 1099511628211ULL;            /* FNV prime    */
   571→    }
   572→    return h;
   573→}
   574→
   575→/* Resize hash table (called under write lock) */
   576→static int mm_cache_grow_table(mm_cache_t *c, size_t new_size)
   577→{
   578→    mm_cache_entry_t **new_tbl = calloc(new_size, sizeof(*new_tbl));
   579→    if (!new_tbl)
   580→        return ENOMEM;
   581→
   582→    if (c->table) {
   583→        for (size_t i = 0; i < c->tbl_size; ++i) {
   584→            mm_cache_entry_t *e = c->table[i];
   585→            if (!e) continue;
   586→
   587→            size_t idx = mm_fnv1a_hash(e->key, strlen(e->key)) & (new_size - 1);
   588→            while (new_tbl[idx])
   589→                idx = (idx + 1) & (new_size - 1);
   590→            new_tbl[idx] = e;
   591→        }
   592→        free(c->table);
   593→    }
   594→    c->table    = new_tbl;
   595→    c->tbl_size = new_size;
   596→    return 0;
   597→}
   598→
   599→/* Move entry to head (MRU) */
   600→static void mm_cache_lru_touch(mm_cache_t *c, mm_cache_entry_t *e)
   601→{
   602→    if (e == c->lru_head) return; /* already MRU */
   603→
   604→    /* detach */
   605→    if (e->prev) e->prev->next = e->next;
   606→    if (e->next) e->next->prev = e->prev;
   607→    if (e == c->lru_tail) c->lru_tail = e->prev;
   608→
   609→    /* insert at head */
   610→    e->prev = NULL;
   611→    e->next = c->lru_head;
   612→    if (c->lru_head) c->lru_head->prev = e;
   613→    c->lru_head = e;
   614→    if (!c->lru_tail) c->lru_tail = e;
   615→}
   616→
   617→/* Evict until under capacity constraints */
   618→static void mm_cache_evict_if_needed(mm_cache_t *c, size_t add_bytes)
   619→{
   620→    while ( (c->entry_count >= c->max_entries) ||
   621→            (c->current_bytes + add_bytes > c->capacity_bytes) )
   622→    {
   623→        mm_cache_entry_t *victim = c->lru_tail;
   624→        if (!victim) break; /* Shouldn't happen */
   625→
   626→        /* Detach from list */
   627→        if (victim->prev) victim->prev->next = NULL;
   628→        c->lru_tail = victim->prev;
   629→        if (victim == c->lru_head)
   630→            c->lru_head = NULL;
   631→
   632→        /* Remove from hash table */
   633→        size_t idx = mm_fnv1a_hash(victim->key, strlen(victim->key)) & (c->tbl_size - 1);
   634→        while (c->table[idx] && c->table[idx] != victim)
   635→            idx = (idx + 1) & (c->tbl_size - 1);
   636→        if (c->table[idx] == victim)
   637→            c->table[idx] = NULL;
   638→
   639→        /* Rehash cluster to fill holes */
   640→        size_t j = (idx + 1) & (c->tbl_size - 1);
   641→        while (c->table[j]) {
   642→            mm_cache_entry_t *move = c->table[j];
   643→            c->table[j] = NULL;
   644→
   645→            size_t new_idx = mm_fnv1a_hash(move->key, strlen(move->key)) & (c->tbl_size - 1);
   646→            while (c->table[new_idx])
   647→                new_idx = (new_idx + 1) & (c->tbl_size - 1);
   648→            c->table[new_idx] = move;
   649→
   650→            j = (j + 1) & (c->tbl_size - 1);
   651→        }
   652→
   653→        c->entry_count--;
   654→        c->current_bytes -= victim->payload_len;
   655→        c->evictions++;
   656→
   657→        mm_log(LOG_DEBUG, "Cache evicted key=%s (payload=%zuB)", victim->key, victim->payload_len);
   658→
   659→        free(victim->key);
   660→        free(victim->payload);
   661→        free(victim->content_type);
   662→        free(victim->etag);
   663→        free(victim);
   664→
   665→        if (c->entry_count == 0)
   666→            break;
   667→    }
   668→}
