 */
void mm_cache_destroy(mm_cache_t *c)
{
    if (!c) return;

    pthread_rwlock_wrlock(&c->rwlock);

    for (size_t i = 0; i < c->tbl_size; ++i) {
        mm_cache_entry_t *e = c->table[i];
        if (e) {
