            /* Rehash cluster (Robin Hood deletion not necessary for small table) */
            size_t j = (idx + 1) & (c->tbl_size - 1);
            while (c->table[j]) {
                mm_cache_entry_t *move = c->table[j];
                c->table[j] = NULL;

                size_t new_idx = mm_fnv1a_hash(move->key, strlen(move->key)) & (c->tbl_size - 1);
