            new_idx = (new_idx + 1) & (c->tbl_size - 1);
        c->table[new_idx] = move;

        j = (j + 1) & (c->tbl_size - 1);
    }

    free(e->key);
    free(e->payload);
    free(e->content_type);
    free(e->etag);
    free(e);

