    pthread_rwlock_rdlock((pthread_rwlock_t *)&c->rwlock);

    out->hits          = c->hits;
    out->misses        = c->misses;
    out->evictions     = c->evictions;
    out->entry_count   = c->entry_count;
    out->current_bytes = c->current_bytes;

