                break;                                                   \
            }                                                            \
            _hf_hh = _hf_hh->hh_next;                                    \
        }                                                                \
    }                                                                    \
} while(0)

#define HASH_ADD_KEYPTR(hhname,keyptr,keylen_in,out) _uthash_add(hhname,keyptr,keylen_in,out)

#define HASH_DEL(head,delptr) _uthash_delete((head)->tbl,&((delptr)->hh))
