    time_t   now  = time(NULL);

    pthread_mutex_lock(&cache->mtx);
    cache_entry_t *ce = hash_lookup(cache, key);

    if (ce && ce->expiry >= now)
    {
        /* Hit */
        copy = malloc(ce->blob_len);
        if (copy)
        {
            memcpy(copy, ce->blob, ce->blob_len);
            if (out_len) *out_len = ce->blob_len;
