        if (ce->prev) ce->prev->next = ce->next;
        if (ce->next) ce->next->prev = ce->prev;
        if (cache->lru_head == ce) cache->lru_head = ce->next;
        if (cache->lru_tail == ce) cache->lru_tail = ce->prev;

