void mercury_cache_shutdown(void)
{
    if (!g_cache_initialised) return;

    pthread_rwlock_wrlock(&g_cache.lock);

    for (size_t i = 0; i < g_cache.bucket_count; ++i) {
        cache_entry_t *e = g_cache.buckets[i];
        if (e) {
            entry_destroy(e);
