    }
    free(g_cache.buckets);
    g_cache.buckets = NULL;
    g_cache.bucket_count = g_cache.size = 0;

    pthread_rwlock_unlock(&g_cache.lock);
    pthread_rwlock_destroy(&g_cache.lock);

    g_cache_initialised = false;
