    pthread_mutex_lock(&cache->mtx);

    lru_purge_expired(cache);

    mm_cache_entry_t *e = NULL;
    HASH_FIND_STR(cache->map, key, e);
    if (!e) {
        mm_metric_inc(cache->m_misses, 1);
        rc = ENOENT;
        goto done;
    }

    if (e->expire_ts <= time(NULL)) {
