    return rc;
}

void mm_cache_clear(mm_cache_t *cache)
{
    if (!cache) return;

    pthread_mutex_lock(&cache->mtx);
    mm_cache_entry_t *cur, *tmp;
    HASH_ITER(hh, cache->map, cur, tmp) { evict_entry(cache, cur); }
    pthread_mutex_unlock(&cache->mtx);

