    pthread_rwlock_wrlock(&c->rwlock);

    for (size_t i = 0; i < c->n_buckets; ++i) {
        entry_t *e = c->buckets[i];
        while (e) {
            entry_t *next = e->h_next;
            free(e->payload);
            free(e->key);
            free(e);
            e = next;
